public interface IChatMediator {
  void Send(string message, User sender);
}

public class ChatRoom : IChatMediator {
  private readonly List<User> _users = new();
  public void Register(User user) => _users.Add(user);
  public void Send(string message, User sender) {
    foreach (var user in _users.Where(u => u != sender)) user.Receive(message);
  }
}

public class User {
  private readonly IChatMediator _mediator;
  public string Name { get; }
  public User(string name, IChatMediator mediator) { Name = name; _mediator = mediator; }
  public void Send(string message) => _mediator.Send(message, this);
  public void Receive(string message) => Console.WriteLine($"{Name} received: {message}");
}

